operations.reducer:
if (state.pledgedAmount !== null) throw new PledgeAlreadyProposedError('Pledge has already been proposed');
state.contributorProfileId = action.input.contributorProfileId;
state.pledgedAmount = action.input.pledgedAmount;
state.asset = {
  symbol: action.input.asset.symbol,
  chainId: action.input.asset.chainId,
  address: action.input.asset.address ?? null,
};
if (action.input.publicNotes) state.publicNotes = action.input.publicNotes;
if (action.input.internalNotes) state.internalNotes = action.input.internalNotes;

operations.schema:
input PledgeAssetInput {
    symbol: String!
    address: EthereumAddress
    chainId: Int!
}

input ProposePledgeInput {
    contributorProfileId: PHID!
    pledgedAmount: Amount_Tokens!
    asset: PledgeAssetInput!
    publicNotes: String
    internalNotes: String
}

operations.reducer:
state.governance = {
  platform: action.input.platform,
  proposalUrl: action.input.proposalUrl,
  voteEndDate: action.input.voteEndDate ?? null,
  quorumStatus: action.input.quorumStatus ?? null,
};

operations.schema:
input AttachGovernanceInput {
    platform: GovernancePlatform!
    proposalUrl: URL!
    voteEndDate: DateTime
    quorumStatus: String
}

operations.reducer:
if (state.status !== 'PROPOSED') throw new InvalidStatusTransitionError(`Cannot mark governance pending in status ${state.status}`);
if (!state.governance) throw new GovernanceRequiredForPendingError('Cannot mark governance pending without governance details attached');
state.status = 'GOVERNANCE_PENDING';

if (state.status === 'CANCELLED' || state.status === 'FAILED' || state.status === 'RECEIVED') throw new InvalidStatusTransitionError(`Cannot mark received in terminal status ${state.status}`);
const previouslyReceived = Number(state.receivedAmount ?? 0);
const incoming = Number(action.input.amount);
const newTotal = previouslyReceived + incoming;
if (state.pledgedAmount !== null && newTotal > Number(state.pledgedAmount)) {
  throw new ReceivedExceedsPledgedError(`Cumulative received (${newTotal}) would exceed pledged (${state.pledgedAmount})`);
}
state.receivedAmount = newTotal;
state.receivedAt = action.input.receivedAt;
if (!state.receiptIds.includes(action.input.receiptId)) {
  state.receiptIds.push(action.input.receiptId);
}
state.status = 'RECEIVED';

operations.schema:
input MarkReceivedInput {
    receiptId: PHID!
    receivedAt: DateTime!
    amount: Amount_Tokens!
}

operations.reducer:
if (state.status === 'RECEIVED' || state.status === 'CANCELLED') throw new InvalidStatusTransitionError(`Cannot cancel pledge in status ${state.status}`);
state.status = 'CANCELLED';
if (action.input.reason) state.internalNotes = `${state.internalNotes ?? ''}\n\nCancelled: ${action.input.reason}`.trim();

if (state.status === 'RECEIVED' || state.status === 'FAILED') throw new InvalidStatusTransitionError(`Cannot fail pledge in status ${state.status}`);
state.status = 'FAILED';
if (action.input.reason) state.internalNotes = `${state.internalNotes ?? ''}\n\nFailed: ${action.input.reason}`.trim();

operations.schema:
input EditNotesInput {
    publicNotes: String
    internalNotes: String
}
